<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E06C75;">tx_mbufs</span><span style="color:#ABB2BF;">[idx] </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> m;</span></span>
