<span class="line"><span style="color:#ABB2BF;">    uint32 idx </span><span style="color:#C678DD;">=</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">regs</span><span style="color:#ABB2BF;">[E1000_RDT] </span><span style="color:#C678DD;">+</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">%</span><span style="color:#ABB2BF;"> RX_RING_SIZE;</span></span>
